import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, Tag, Eye, Edit2, Check, X, Calendar
} from 'lucide-react';

// --- CONFIGURACIÓN ---
const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";
const FOLDER_PREFIX = "GALERIA_MAESTRA/"; // <--- CRÍTICO: Esto coincide con tu Cloudinary

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = () => ({ id: Math.random(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [tempData, setTempData] = useState({});

  // --- CARGAR DATOS ---
  const cargarPublicados = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setPublicados(res.data);
    } catch (e) { console.error("Error al cargar publicados", e); }
  }, [localId]);

  useEffect(() => {
    cargarPublicados();
    axios.get(`${API_URL}/api/galeria`).then(res => {
      setGaleria(res.data);
    }).catch(err => console.log("Error en galeria", err));
  }, [cargarPublicados]);

  // --- BUSCADOR DE IMÁGENES INTELIGENTE ---
  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    
    // Normalizamos el texto: quitamos acentos, pasamos a minúsculas y limpiamos símbolos
    const normalizar = (t) => t.toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // Quita acentos
      .replace(/[^a-z0-9]/g, ' '); // Cambia guiones/puntos por espacios

    const textoLimpio = normalizar(texto);
    const palabrasBusqueda = textoLimpio.split(' ').filter(p => p.length > 2);

    return galeria.find(foto => {
      // Comparamos contra el nombre de referencia (que suele tener guiones)
      const nombreFoto = normalizar(foto.nombreReferencia);
      // Si todas las palabras importantes del producto están en el nombre de la foto, es un MATCH
      return palabrasBusqueda.every(palabra => nombreFoto.includes(palabra));
    });
  }, [galeria]);

  // --- MANEJO DE TABLA ---
  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    
    const nuevas = lineas.map(line => {
      const celdas = line.split('\t');
      const nombre = celdas[0] || '';
      const match = buscarMatch(nombre);
      return { 
        ...filaInicial(), 
        id: Math.random(), 
        producto: nombre, 
        precioNuevo: celdas[1] || '', 
        precioViejo: celdas[2] || '', 
        stock: celdas[3] || 0, 
        categoria: celdas[4] || 'Almacén', 
        fotoSugerida: match ? match.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Define fechas de validez");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          categoria: f.categoria,
          publicId: f.fotoSugerida || 'placeholder_id',
          local: localId,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      setFilas([filaInicial()]);
      cargarPublicados();
      alert("¡Publicado con éxito!");
    } catch (e) { alert("Error al publicar"); } finally { setCargando(false); }
  };

  // --- RENDERIZADO DE IMAGEN ---
  const renderFoto = (publicId, size = "w_50,h_50") => {
    if (!publicId || publicId === 'placeholder_id') return <ImageIcon color="#cbd5e1" size={24}/>;
    // Cloudinary necesita el path completo si hay carpetas
    return (
      <img 
        src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill/v1/${publicId}`} 
        style={{ borderRadius: '8px', objectFit: 'cover' }} 
        alt="thumb" 
      />
    );
  };

  return (
    <div style={{ padding: '40px', maxWidth: '1200px', margin: '0 auto', background: '#f8fafc', minHeight: '100vh' }}>
      
      {/* HEADER */}
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
        <button onClick={() => navigate(-1)} style={{ background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' }}>
          <ArrowLeft size={18}/> Volver
        </button>
        {/* BOTÓN RENOMBRADO SEGÚN TU PEDIDO */}
        <button style={{ background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '10px 20px', borderRadius: '12px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <Database size={16}/> Añadir fotos a galería
        </button>
      </div>

      <div style={{ marginBottom: '30px' }}>
        <h1 style={{ color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px' }}><Tag color="#e67e22"/> Gestión de Inventario</h1>
      </div>

      {/* TABLA DE CARGA MASIVA */}
      <div style={{ background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px' }} onPaste={handlePaste}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#f8fafc' }}>
              <th style={{ padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.8rem' }}>Miniatura</th>
              <th style={{ padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.8rem' }}>Producto</th>
              <th style={{ padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.8rem' }}>P. Nuevo</th>
              <th style={{ padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.8rem' }}>P. Viejo</th>
              <th style={{ padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.8rem' }}>Stock</th>
            </tr>
          </thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                <td style={{ padding: '10px' }}>{renderFoto(f.fotoSugerida)}</td>
                <td style={{ padding: '10px' }}>
                  <input 
                    style={{ width: '100%', border: 'none', outline: 'none' }} 
                    value={f.producto} 
                    onChange={e => {
                      const n = [...filas];
                      const idx = n.findIndex(x => x.id === f.id);
                      n[idx].producto = e.target.value;
                      const m = buscarMatch(e.target.value);
                      n[idx].fotoSugerida = m ? m.publicId : null;
                      setFilas(n);
                    }}
                    placeholder="Escribe o pega aquí..."
                  />
                </td>
                <td style={{ padding: '10px' }}><input style={{ width: '60px', border: 'none' }} type="number" value={f.precioNuevo} onChange={e => {const n=[...filas]; n[n.findIndex(x=>x.id===f.id)].precioNuevo=e.target.value; setFilas(n);}}/></td>
                <td style={{ padding: '10px' }}><input style={{ width: '60px', border: 'none' }} type="number" value={f.precioViejo} onChange={e => {const n=[...filas]; n[n.findIndex(x=>x.id===f.id)].precioViejo=e.target.value; setFilas(n);}}/></td>
                <td style={{ padding: '10px' }}><input style={{ width: '60px', border: 'none' }} type="number" value={f.stock} onChange={e => {const n=[...filas]; n[n.findIndex(x=>x.id===f.id)].stock=e.target.value; setFilas(n);}}/></td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{ padding: '20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' }}>
            <div style={{ display: 'flex', gap: '10px' }}>
              <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={{ padding: '8px', borderRadius: '8px', border: '1px solid #ddd' }}/>
              <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={{ padding: '8px', borderRadius: '8px', border: '1px solid #ddd' }}/>
            </div>
            <button onClick={publicarTodo} style={{ background: '#1e293b', color: 'white', padding: '10px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px' }}>
              {cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>} Publicar Ofertas
            </button>
        </div>
      </div>

      {/* CRUD DE PRODUCTOS PUBLICADOS */}
      <h2 style={{ color: '#1e293b', fontSize: '1.4rem', marginBottom: '20px' }}><Eye size={20}/> Productos Activos en la Nube</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' }}>
        {publicados.map(p => (
          <div key={p._id} style={{ background: 'white', padding: '20px', borderRadius: '20px', border: editandoId === p._id ? '2px solid #3b82f6' : '1px solid #e2e8f0', position: 'relative' }}>
            <div style={{ position: 'absolute', top: '10px', right: '10px', display: 'flex', gap: '5px' }}>
              {editandoId === p._id ? (
                <>
                  <button onClick={async () => { await axios.put(`${API_URL}/api/ofertas/${p._id}`, tempData); setEditandoId(null); cargarPublicados(); }} style={{ background: '#dcfce7', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer' }}><Check size={14} color="#16a34a"/></button>
                  <button onClick={() => setEditandoId(null)} style={{ background: '#f1f5f9', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer' }}><X size={14}/></button>
                </>
              ) : (
                <>
                  <button onClick={() => { setEditandoId(p._id); setTempData(p); }} style={{ background: '#eff6ff', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor:'pointer' }}><Edit2 size={14} color="#3b82f6"/></button>
                  <button onClick={async () => { if(window.confirm("¿Borrar?")) { await axios.delete(`${API_URL}/api/ofertas/${p._id}`); cargarPublicados(); } }} style={{ background: '#fee2e2', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor:'pointer' }}><Trash size={14} color="#ef4444"/></button>
                </>
              )}
            </div>
            
            <div style={{ width: '100%', height: '120px', display: 'flex', justifyContent: 'center', marginBottom: '15px' }}>
              {renderFoto(p.publicId, "w_250,h_150")}
            </div>

            {editandoId === p._id ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                <input style={{ padding: '5px', fontSize: '0.8rem' }} value={tempData.producto} onChange={e => setTempData({...tempData, producto: e.target.value})}/>
                <input style={{ padding: '5px', fontSize: '0.8rem' }} type="number" value={tempData.precioNuevo} onChange={e => setTempData({...tempData, precioNuevo: e.target.value})}/>
                <input style={{ padding: '5px', fontSize: '0.8rem' }} type="number" value={tempData.stock} onChange={e => setTempData({...tempData, stock: e.target.value})}/>
              </div>
            ) : (
              <>
                <h4 style={{ margin: '0 0 10px 0', fontSize: '1rem' }}>{p.producto}</h4>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span style={{ fontWeight: 'bold', color: '#e67e22' }}>${p.precioNuevo}</span>
                  <span style={{ fontSize: '0.8rem', color: '#64748b' }}>Stock: {p.stock}</span>
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default GestionOfertas;
